import MarkdownIt from 'markdown-it';

// ✅ 创建单例实例
const md = createMarkdownInstance();

self.onmessage = function (event) {
  const { content, requestId } = event.data;
  try {
    const parsedContent = parseMarkdown(content);
    self.postMessage({ 
      content: parsedContent, 
      requestId: requestId 
    });
  } catch (error) {
    // 错误处理
    console.log('解析错误:', error);
  }
};

const PLACEHOLDER_IMG_WIDTH = 50;
const PLACEHOLDER_IMG_HEIGHT = 50;

// ✅ 单独创建和配置 MarkdownIt 实例
function createMarkdownInstance() {
  const mdInstance = new MarkdownIt();

  // 只注册一次插件
  mdInstance.use((md) => {
    const defaultRender =
      md.renderer.rules.fence ||
      function (tokens, idx, options, env, self) {
        return self.renderToken(tokens, idx, options);
      };

    // 图片渲染规则
    md.renderer.rules.image = function (tokens, idx, options, env, self) {
      const token = tokens[idx];
      const srcIndex = token.attrIndex('src');
      
      // 使用占位图片
      token.attrs[srcIndex][1] = getPlaceholderImage();
      
      // 设置尺寸
      setTokenAttribute(token, 'width', PLACEHOLDER_IMG_WIDTH.toString());
      setTokenAttribute(token, 'height', PLACEHOLDER_IMG_HEIGHT.toString());

      return self.renderToken(tokens, idx, options);
    };

    // 代码块渲染规则
    md.renderer.rules.fence = function (tokens, idx, options, env, self) {
      const token = tokens[idx];
      const language = token.info || '';
      const originalContent = token.content;

      const copyButtonHtml = `<button class="copy-button" data-code="${encodeURIComponent(originalContent)}">复制</button>`;
      const defaultCodeBlockHtml = defaultRender(tokens, idx, options, env, self);

      return `<div class="code-block">
                <div class="top-bark">${language}${copyButtonHtml}</div>
                <div class="show-scrollbar">${defaultCodeBlockHtml}</div>
              </div>`;
    };
  });

  return mdInstance;
}

// ✅ 提取占位图片到常量，避免重复创建长字符串
const PLACEHOLDER_IMAGE = 'data:image/png;base64,';

function getPlaceholderImage() {
  return PLACEHOLDER_IMAGE;
}

// ✅ 辅助函数，避免重复代码
function setTokenAttribute(token, name, value) {
  const index = token.attrIndex(name);
  if (index < 0) {
    token.attrPush([name, value]);
  } else {
    token.attrs[index][1] = value;
  }
}

// ✅ 简化的解析函数
function parseMarkdown(content) {
  return md.render(content);
}